        // We need ans[j] = nums[n - (j - n) - 1] = nums[2*n - j - 1]
        // A simpler way is to iterate over the indices of the second half:
        // Index in ans: k from n to 2n - 1
        // Corresponding index in nums: n - 1 - (k - n) = 2n - 1 - k

        const k = i + n; // Index in ans (n to 2n-1)
        const reverse_index = n - 1 - i; // Index in nums (n-1 down to 0)
        ans[k] = nums[reverse_index];
    }

    return ans;
}

